import{_ as e,o as t,c as r,a2 as o}from"./chunks/framework.IfsbZ5bg.js";const q=JSON.parse('{"title":"荆州早报 | 2026年6月3日","description":"","frontmatter":{"title":"2026-06-03T00:00:00.000Z","date":"2026-06-03T00:00:00.000Z","categories":["chaojian"],"tags":["朝鉴","趋势洞察","新闻","经济"],"author":"银枢局"},"headers":[],"relativePath":"posts/zhaojian/zhaojian-2026-06-03.md","filePath":"posts/zhaojian/zhaojian-2026-06-03.md"}'),h={name:"posts/zhaojian/zhaojian-2026-06-03.md"};function n(l,a,s,i,p,c){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="荆州早报-2026年6月3日" tabindex="-1">荆州早报 | 2026年6月3日 <a class="header-anchor" href="#荆州早报-2026年6月3日" aria-label="Permalink to &quot;荆州早报 | 2026年6月3日&quot;">​</a></h1><blockquote><p>🌅 朝鉴 · 朝闻天下，鉴往知来</p></blockquote><hr><h2 id="📰-今日荆州十大热点" tabindex="-1">📰 今日荆州十大热点 <a class="header-anchor" href="#📰-今日荆州十大热点" aria-label="Permalink to &quot;📰 今日荆州十大热点&quot;">​</a></h2><h3 id="_1️⃣-荆州入选国家级城市更新试点-喜获10亿元中央专项资金" tabindex="-1">1️⃣ 荆州入选国家级城市更新试点，喜获10亿元中央专项资金 <a class="header-anchor" href="#_1️⃣-荆州入选国家级城市更新试点-喜获10亿元中央专项资金" aria-label="Permalink to &quot;1️⃣ 荆州入选国家级城市更新试点，喜获10亿元中央专项资金&quot;">​</a></h3><p>近日，财政部、住建部公布2026年城市更新行动试点名单，荆州市成功入选全国15个国家级试点城市之一，将获得10亿元中央财政专项资金支持。每省仅能推荐1个城市参评，竞争激烈。市委、市政府高度重视，构建&quot;领导小组统筹+部门协同+专项资金支持&quot;推进体系，全力争取试点落地。资金将重点用于城市基础设施建设、老旧小区改造、历史文化保护等领域，推动荆州城市更新迈入国家级示范行列。</p><p>🔗 <a href="http://news.jznews.com.cn/system/2026/06/02/030132551.shtml" target="_blank" rel="noreferrer">荆州新闻网</a></p><hr><h3 id="_2️⃣-市长李迎伟调度2026年全市高考筹备工作" tabindex="-1">2️⃣ 市长李迎伟调度2026年全市高考筹备工作 <a class="header-anchor" href="#_2️⃣-市长李迎伟调度2026年全市高考筹备工作" aria-label="Permalink to &quot;2️⃣ 市长李迎伟调度2026年全市高考筹备工作&quot;">​</a></h3><p>6月1日，市委副书记、市长李迎伟调度2026年全市高考筹备工作，强调要全力以赴确保高考安全、平稳、公平、有序。要求做到试卷保密万无一失、极端天气应对有方、涉考舆情处置有力，坚持&quot;人防、物防、技防&quot;三防联动，严把入场安检关口，以考生为中心做好暖心关怀。</p><p>🔗 <a href="http://news.jznews.com.cn/system/2026/06/02/030132552.shtml" target="_blank" rel="noreferrer">荆州新闻网</a></p><hr><h3 id="_3️⃣-2026年荆州高中阶段学校招生方案公布" tabindex="-1">3️⃣ 2026年荆州高中阶段学校招生方案公布 <a class="header-anchor" href="#_3️⃣-2026年荆州高中阶段学校招生方案公布" aria-label="Permalink to &quot;3️⃣ 2026年荆州高中阶段学校招生方案公布&quot;">​</a></h3><p>荆州市教育局发布2026年高中阶段学校招生方案。省级重点高中荆州中学面向荆州区、江陵县、松滋市、公安县、石首市、监利市和洪湖市招生；沙市中学面向沙市区（含经开区）及周边县市区招生。民办高中、市体育运动学校面向全市招生。严格落实阳光招生、属地招生原则，不得违规跨区域招生。</p><p>🔗 <a href="http://news.jznews.com.cn/system/2026/06/02/030132547.shtml" target="_blank" rel="noreferrer">荆州新闻网</a></p><hr><h3 id="_4️⃣-市政府与湖北水发集团签订战略合作协议" tabindex="-1">4️⃣ 市政府与湖北水发集团签订战略合作协议 <a class="header-anchor" href="#_4️⃣-市政府与湖北水发集团签订战略合作协议" aria-label="Permalink to &quot;4️⃣ 市政府与湖北水发集团签订战略合作协议&quot;">​</a></h3><p>6月2日，荆州市政府与湖北水发集团签订战略合作协议，双方围绕重大水利基础设施建设、城乡供水一体化、农业水利现代化等领域深化合作，共同推动荆州水利事业高质量发展。市长李迎伟表示，荆州作为全省水利发展重点城市，具备独特优势和广阔空间，希望水发集团加大在荆投资布局力度。</p><p>🔗 <a href="http://news.jznews.com.cn/system/2026/06/02/030132593.shtml" target="_blank" rel="noreferrer">荆州新闻网</a></p><hr><h3 id="_5️⃣-洪湖农商银行-深耕莲藕特色链-书写水乡共富答卷" tabindex="-1">5️⃣ 洪湖农商银行：深耕莲藕特色链 书写水乡共富答卷 <a class="header-anchor" href="#_5️⃣-洪湖农商银行-深耕莲藕特色链-书写水乡共富答卷" aria-label="Permalink to &quot;5️⃣ 洪湖农商银行：深耕莲藕特色链 书写水乡共富答卷&quot;">​</a></h3><p>洪湖农商银行以莲藕产业为核心，深耕特色农业产业链，创新推出&quot;莲藕贷&quot;专属信贷产品，全力支持莲藕种植、加工、销售全链条发展。目前洪湖莲藕种植面积达22万亩，年产量30万吨，产业综合产值120亿元，产品远销海内外，成为带动农户增收致富的&quot;金钥匙&quot;。</p><p>🔗 <a href="http://news.jznews.com.cn/system/2026/06/02/030132597.shtml" target="_blank" rel="noreferrer">荆州新闻网</a></p><hr><h3 id="_6️⃣-金声奖-获奖者走读长江-汇聚荆州千年古城" tabindex="-1">6️⃣ &quot;金声奖&quot;获奖者走读长江，汇聚荆州千年古城 <a class="header-anchor" href="#_6️⃣-金声奖-获奖者走读长江-汇聚荆州千年古城" aria-label="Permalink to &quot;6️⃣ &quot;金声奖&quot;获奖者走读长江，汇聚荆州千年古城&quot;">​</a></h3><p>中国播音主持界最高荣誉&quot;金声奖&quot;的20余位获奖者从全国各地汇聚荆州，开启&quot;走读长江文化 看见支点湖北&quot;主题基层行走活动。活动由湖北省广播电视局主办，湖北广播电视台、荆州市委宣传部承办，这是&quot;金声奖&quot;获奖者首次以群体身份集体走进基层、走近长江。</p><p>🔗 <a href="http://news.jznews.com.cn/system/2026/06/02/030132590.shtml" target="_blank" rel="noreferrer">荆州新闻网</a></p><hr><h3 id="_7️⃣-省运会足球u13比赛落幕-荆州代表队夺得亚军" tabindex="-1">7️⃣ 省运会足球U13比赛落幕，荆州代表队夺得亚军 <a class="header-anchor" href="#_7️⃣-省运会足球u13比赛落幕-荆州代表队夺得亚军" aria-label="Permalink to &quot;7️⃣ 省运会足球U13比赛落幕，荆州代表队夺得亚军&quot;">​</a></h3><p>6月1日，湖北省第十七届运动会青少年体育类（体校组）足球男子U13比赛落幕，荆州代表队夺得亚军。赛事中荆州队小组赛全胜出线，半决赛2:0战胜对手，决赛0:1惜败武汉队，展现顽强拼搏精神。</p><p>🔗 <a href="http://news.jznews.com.cn/system/2026/06/02/030132588.shtml" target="_blank" rel="noreferrer">荆州新闻网</a></p><hr><h3 id="_8️⃣-创意筑城出绝活-00后博主用3亿个方块-手搓-荆州城" tabindex="-1">8️⃣ 创意筑城出绝活！00后博主用3亿个方块&quot;手搓&quot;荆州城 <a class="header-anchor" href="#_8️⃣-创意筑城出绝活-00后博主用3亿个方块-手搓-荆州城" aria-label="Permalink to &quot;8️⃣ 创意筑城出绝活！00后博主用3亿个方块&quot;手搓&quot;荆州城&quot;">​</a></h3><p>00后团队@筑·builders历时28天，用3亿个方块在游戏Minecraft中1:1还原荆州古城，涵盖宾阳楼、古城墙、老建筑等标志性景观，细腻呈现荆州千年古韵。作品将在荆州古城景区展出，并通过&quot;数字古城&quot;全球创意大赛推广荆州文化。</p><p>🔗 <a href="http://news.jznews.com.cn/system/2026/06/02/030132579.shtml" target="_blank" rel="noreferrer">荆州新闻网</a></p><hr><h3 id="_9️⃣-网暴抗洪救灾村支书的涉事人员被查处" tabindex="-1">9️⃣ 网暴抗洪救灾村支书的涉事人员被查处 <a class="header-anchor" href="#_9️⃣-网暴抗洪救灾村支书的涉事人员被查处" aria-label="Permalink to &quot;9️⃣ 网暴抗洪救灾村支书的涉事人员被查处&quot;">​</a></h3><p>荆州市对网暴抗洪救灾村支书的涉事人员进行严肃查处，依法依规追究相关责任，维护抗洪一线基层干部的合法权益和社会正气。</p><p>🔗 <a href="http://news.jznews.com.cn/system/2026/06/02/030132595.shtml" target="_blank" rel="noreferrer">荆州新闻网</a></p><hr><h3 id="🔟-湖北匠心闪耀世界杯-荆州足球雕塑将飞越太平洋" tabindex="-1">🔟 湖北匠心闪耀世界杯：荆州足球雕塑将飞越太平洋 <a class="header-anchor" href="#🔟-湖北匠心闪耀世界杯-荆州足球雕塑将飞越太平洋" aria-label="Permalink to &quot;🔟 湖北匠心闪耀世界杯：荆州足球雕塑将飞越太平洋&quot;">​</a></h3><p>为2026年美加墨世界杯定制的巨型足球雕塑出自湖北工匠之手，每一片六边形组件都需承受上万次精准锤击。荆州作为湖北省足球联赛重要城市，工匠精神与足球热情交相辉映，钢铁足球即将远渡重洋，展现荆楚文化魅力。</p><p>🔗 <a href="https://k.sina.com.cn/article_7879995911_1d5af320706801xdrq.html?from=sports&amp;subch=osport" target="_blank" rel="noreferrer">新浪网</a></p><hr><h2 id="📋-荆州快讯" tabindex="-1">📋 荆州快讯 <a class="header-anchor" href="#📋-荆州快讯" aria-label="Permalink to &quot;📋 荆州快讯&quot;">​</a></h2><ul><li>市直事业单位2026年人才引进拟聘用人员公示（第一批），公示期6月2日-8日</li><li>汪元程主持研究全市平台公司招商和经开区招商工作</li><li>市委常委会开展树立和践行正确政绩观学习教育第二次专题研讨</li><li>外卖电动车街头突发自燃，热心市民紧急施救</li></ul><hr><blockquote><p>📅 2026年6月3日 · 星期三<br> 🏛 数据来源：荆州新闻网、荆州市人民政府网、新浪网<br> 🤖 本报由 QClaw 自动采集整理</p></blockquote>',48)])])}const d=e(h,[["render",n]]);export{q as __pageData,d as default};
